-- RX Team — Етап 40 (SVG-іконки медалей для всіх 11 ачивок → achievements.thumbnail_svg).
-- Виконати в Supabase → SQL Editor ПІСЛЯ etap39.sql. Ідемпотентно (UPDATE, base64 без лапок).
--
-- Джерело: assets/achievement-icons/<code>.svg (медаль: метал за tier + лавровий вінок + символ теми).
-- Стиль: docs/prompts/ACHIEVEMENT_ICON_PROMPT.md. Іконки далі редагуються в /admin/achievements.

update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'first_contact';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'deploy_10';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'deploy_25';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'deploy_50';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'recruiter';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'dawn_patrol';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'iron_discipline';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'msg_100';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'msg_1000';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'msg_5000';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'msg_10000';
